import java.util.ArrayList;import java.util.List;import java.util.Map;
final class BridgePattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}
  interface Channel{String send(String recipient,String message);}static final class EmailChannel implements Channel{public String send(String r,String m){return"email:"+r+":"+m;}}static final class SlackChannel implements Channel{public String send(String r,String m){return"slack:"+r+":"+m;}}
  abstract static class Alert{private final Channel channel;Alert(Channel c){channel=c;}abstract String prefix();String deliver(String recipient,String body){return channel.send(recipient,prefix()+" "+body);}}static final class IncidentAlert extends Alert{IncidentAlert(Channel c){super(c);}String prefix(){return"[INCIDENT]";}}static final class ReminderAlert extends Alert{ReminderAlert(Channel c){super(c);}String prefix(){return"[REMINDER]";}}
  @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){List<String>out=new ArrayList<>();for(Map<String,Object>item:(List<Map<String,Object>>)input.getOrDefault("notifications",List.of())){Channel channel=switch(String.valueOf(item.get("channel"))){case"email"->new EmailChannel();case"slack"->new SlackChannel();default->throw new PatternException("unsupported_channel");};Alert alert=switch(String.valueOf(item.get("kind"))){case"incident"->new IncidentAlert(channel);case"reminder"->new ReminderAlert(channel);default->throw new PatternException("unsupported_alert");};out.add(alert.deliver(String.valueOf(item.get("recipient")),String.valueOf(item.get("body"))));}return Map.of("deliveries",out);}}
